tlDataChunk*
tlFlexibleObjectChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Simulation::Flexible::FIX_PARTICLE:
        dch = new tlFlexibleObjectFixParticleChunk(&ch);
        break;
    case Simulation::Flexible::MAP_VL:
        dch = new tlFlexibleObjectMapToVLChunk(&ch);
        break;
    case Simulation::Flexible::TRI_MAP:
        dch = new tlFlexibleObjectTriMapChunk(&ch);
        break;
    case Simulation::Flexible::EDGE_MAP:
        dch = new tlFlexibleObjectEdgeMapChunk(&ch);
        break;
    case Simulation::Flexible::EDGE_LEN:
        dch = new tlFlexibleObjectEdgeLengthChunk(&ch);
        break;
    case Simulation::Flexible::OBJECT_PARAMETERS:
        dch = new tlFlexibleObjectParamChunk(&ch);
        break;
    case Simulation::Flexible::OBJECT_LAMBDA:
        dch = new tlFlexibleLambdaObjectParamChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

