int tlFlexibleObjectFixParticleChunk::sortPriority = -1;

tlFlexibleObjectFixParticleChunk::tlFlexibleObjectFixParticleChunk()
{
    Init();
}

tlFlexibleObjectFixParticleChunk::tlFlexibleObjectFixParticleChunk(const tlFlexibleObjectFixParticleChunk& ch)
{
    Init();
    *this = ch;
}

tlFlexibleObjectFixParticleChunk::~tlFlexibleObjectFixParticleChunk()
{

    if(fixparticle != NULL){
        delete[] fixparticle;
    }
}

tlFlexibleObjectFixParticleChunk::tlFlexibleObjectFixParticleChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Flexible::FIX_PARTICLE);
    ident = Simulation::Flexible::FIX_PARTICLE;

    tlFile* f = ch->GetFile();
    unsigned int i;

    fixparticlecount = f->GetWord();
    fixparticle = new unsigned short[fixparticlecount];
    for(i = 0; i < fixparticlecount; i++)
    {
        fixparticle[i] = f->GetWord();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::FIX_PARTICLE);
    }
}

void
tlFlexibleObjectFixParticleChunk::Init()
{
    ident = Simulation::Flexible::FIX_PARTICLE;
    fixparticlecount = 0;
    fixparticle = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::FIX_PARTICLE);
    }
}

long 
tlFlexibleObjectFixParticleChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( fixparticlecount );
    for(i = 0; i < (int)fixparticlecount; i++)
    {
        s += sizeof( fixparticle[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlFlexibleObjectFixParticleChunk&
tlFlexibleObjectFixParticleChunk::operator=(const tlFlexibleObjectFixParticleChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    fixparticlecount = a.fixparticlecount;
    if(fixparticle)
    {
        delete fixparticle;
    }
    fixparticle = new unsigned short[fixparticlecount];
    for( i = 0; i < fixparticlecount ; i++ )
    {
        fixparticle[i] = a.fixparticle[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlFlexibleObjectFixParticleChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlFlexibleObjectFixParticleChunk* aptr = dynamic_cast<const tlFlexibleObjectFixParticleChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(fixparticlecount == aptr->fixparticlecount))
    {
        return false;
    }
    for(i = 0; i < fixparticlecount; i++)
    {
        if(!(fixparticle[i] == aptr->fixparticle[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlFlexibleObjectFixParticleChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


