tlFlexibleObjectTriMapChunk::tlFlexibleObjectTriMapChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Flexible::TRI_MAP);
    ident = Simulation::Flexible::TRI_MAP;

    tlFile* f = ch->GetFile();
    unsigned int i;

    trimapcount = f->GetWord();
    trimap = new FlexibleObjectTriMapData[trimapcount];
    for(i = 0; i < trimapcount; i++)
    {
        trimap[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::TRI_MAP);
    }
}

