// tlFlexibleLambdaObjectParamChunk

int tlFlexibleLambdaObjectParamChunk::sortPriority = -1;

tlFlexibleLambdaObjectParamChunk::tlFlexibleLambdaObjectParamChunk()
{
    Init();
}

tlFlexibleLambdaObjectParamChunk::tlFlexibleLambdaObjectParamChunk(const tlFlexibleLambdaObjectParamChunk& ch)
{
    Init();
    *this = ch;
}

tlFlexibleLambdaObjectParamChunk::~tlFlexibleLambdaObjectParamChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlFlexibleLambdaObjectParamChunk::tlFlexibleLambdaObjectParamChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Flexible::OBJECT_LAMBDA);
    ident = Simulation::Flexible::OBJECT_LAMBDA;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    lambdaf = f->GetFloat();
    lambdad = f->GetFloat();
    kappaf = f->GetFloat();
    kappad = f->GetFloat();
    iotaf = f->GetFloat();
    iotad = f->GetFloat();
    wind1dkf = f->GetFloat();
    wind2dkf = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::OBJECT_LAMBDA);
    }
}

void
tlFlexibleLambdaObjectParamChunk::Init()
{
    ident = Simulation::Flexible::OBJECT_LAMBDA;
    name = NULL;
    lambdaf = 0.0f;
    lambdad = 0.0f;
    kappaf = 0.0f;
    kappad = 0.0f;
    iotaf = 0.0f;
    iotad = 0.0f;
    wind1dkf = 0.0f;
    wind2dkf = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::OBJECT_LAMBDA);
    }
}

long 
tlFlexibleLambdaObjectParamChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( lambdaf );
    s += sizeof( lambdad );
    s += sizeof( kappaf );
    s += sizeof( kappad );
    s += sizeof( iotaf );
    s += sizeof( iotad );
    s += sizeof( wind1dkf );
    s += sizeof( wind2dkf );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlFlexibleLambdaObjectParamChunk&
tlFlexibleLambdaObjectParamChunk::operator=(const tlFlexibleLambdaObjectParamChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    lambdaf = a.lambdaf;
    lambdad = a.lambdad;
    kappaf = a.kappaf;
    kappad = a.kappad;
    iotaf = a.iotaf;
    iotad = a.iotad;
    wind1dkf = a.wind1dkf;
    wind2dkf = a.wind2dkf;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlFlexibleLambdaObjectParamChunk::operator==(const tlDataChunk& a)
{

    const tlFlexibleLambdaObjectParamChunk* aptr = dynamic_cast<const tlFlexibleLambdaObjectParamChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(lambdaf == aptr->lambdaf))
    {
        return false;
    }
    if(!(lambdad == aptr->lambdad))
    {
        return false;
    }
    if(!(kappaf == aptr->kappaf))
    {
        return false;
    }
    if(!(kappad == aptr->kappad))
    {
        return false;
    }
    if(!(iotaf == aptr->iotaf))
    {
        return false;
    }
    if(!(iotad == aptr->iotad))
    {
        return false;
    }
    if(!(wind1dkf == aptr->wind1dkf))
    {
        return false;
    }
    if(!(wind2dkf == aptr->wind2dkf))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlFlexibleLambdaObjectParamChunk::NameCompare(const tlDataChunk& a)
{

    const tlFlexibleLambdaObjectParamChunk* aptr = dynamic_cast<const tlFlexibleLambdaObjectParamChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlFlexibleLambdaObjectParamChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlFlexibleLambdaObjectParamChunk(ch);
    return dtCh;
}

void
tlFlexibleLambdaObjectParamChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutFloat(lambdaf);
        f->PutFloat(lambdad);
        f->PutFloat(kappaf);
        f->PutFloat(kappad);
        f->PutFloat(iotaf);
        f->PutFloat(iotad);
        f->PutFloat(wind1dkf);
        f->PutFloat(wind2dkf);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlFlexibleLambdaObjectParamChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlFlexibleLambdaObjectParamChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name     = \"%s\"\n",indent,"",name);
    printf("%*s  LambdaF  = %f\n",indent,"",lambdaf);
    printf("%*s  LambdaD  = %f\n",indent,"",lambdad);
    printf("%*s  KappaF   = %f\n",indent,"",kappaf);
    printf("%*s  KappaD   = %f\n",indent,"",kappad);
    printf("%*s  IotaF    = %f\n",indent,"",iotaf);
    printf("%*s  IotaD    = %f\n",indent,"",iotad);
    printf("%*s  Wind1DKf = %f\n",indent,"",wind1dkf);
    printf("%*s  Wind2DKf = %f\n",indent,"",wind2dkf);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlFlexibleLambdaObjectParamChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name    \n",indent,"",name);
    printf("%*s  float %12f # LambdaF \n",indent,"",lambdaf);
    printf("%*s  float %12f # LambdaD \n",indent,"",lambdad);
    printf("%*s  float %12f # KappaF  \n",indent,"",kappaf);
    printf("%*s  float %12f # KappaD  \n",indent,"",kappad);
    printf("%*s  float %12f # IotaF   \n",indent,"",iotaf);
    printf("%*s  float %12f # IotaD   \n",indent,"",iotad);
    printf("%*s  float %12f # Wind1DKf\n",indent,"",wind1dkf);
    printf("%*s  float %12f # Wind2DKf\n",indent,"",wind2dkf);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

